func TestSessionMaxVisibleItems(t *testing.T) {
	tests := []struct {
		name   string
		height int
		want   int
	}{
		{
			name:   "zero height returns fallback",
			height: 0,
			want:   10,
		},
		{
			name:   "small window",
			height: 12, // contentHeight = 10, overhead = 6 (header 3 + footer 3), available = 4
			want:   4,
		},
		{
			name:   "large window uses all space",
			height: 50, // contentHeight = 48, overhead = 6, available = 42
			want:   42,
		},
		{
			name:   "very small window",
			height: 10, // contentHeight = 8, overhead = 6, available = 2
			want:   2,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			cfg := config.DefaultConfig()
			m := Model{
				height: tt.height,
				config: cfg,
			}
			got := m.sessionMaxVisibleItems()
			if got != tt.want {
				t.Errorf("sessionMaxVisibleItems() with height=%d = %d, want %d",
					tt.height, got, tt.want)
			}
		})
	}
}

func TestProjectMaxVisibleItems(t *testing.T) {
	tests := []struct {
		name   string
		height int
		want   int
	}{
		{
			name:   "zero height returns fallback",
			height: 0,
			want:   10,
		},
		{
			name:   "small window",
			height: 12, // contentHeight = 10, overhead = 6 (header 3 + footer 3), available = 4
			want:   4,
		},
