		for _, line := range strings.Split(btn, "\n") {
			lines = append(lines, " "+line)
		}
		if i < len(actions)-1 {
			lines = append(lines, "") // gap between buttons
		}
	}

	content := strings.Join(lines, "\n")
	return RenderSectionBox("ACTIONS", content, boxWidth, SectionBoxOpts{})
}

